import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"肌肉大猩猩","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/肌肉大猩猩.md","filePath":"4.资源分区/6.技艺及称号/杂项/肌肉大猩猩.md"}'),d={name:"4.资源分区/6.技艺及称号/杂项/肌肉大猩猩.md"};function p(_,e,l,h,i,c){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"肌肉大猩猩",tabindex:"-1"},[n("肌肉大猩猩 "),a("a",{class:"header-anchor",href:"#肌肉大猩猩","aria-label":'Permalink to "肌肉大猩猩"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="肌肉大猩猩-1" tabindex="-1">肌肉大猩猩 <a class="header-anchor" href="#肌肉大猩猩-1" aria-label="Permalink to &quot;肌肉大猩猩&quot;">​</a></h1><p>肌肉大猩猩<br> 兑换前提：需求力量9以上 智力低于力量5点<br> C+1000<br> 特异本质<br> ”大力才能出奇迹！“<br> “只要努力，就没有什么做不到！”<br> “你TM脑子里也都是肌肉吧！”</p><p>效果：你简直是字面意义上的脑子里都是肌肉的代表，在如同单细胞一般固执的认为只要收紧肌肉，延髓反射和身体本能就可以做到一切。久而久之，也许是老天垂怜你这个蠢货，导致你真的拥有了神奇的能力。<br> 人物可以以力量属性代替智力属性进行检定，这需要获得本能力时选择是对于哪一方面的代替（如：施法、造物、或某个特定技能），以运动技能代替学识技能参与主动发起的鉴定。</p><p>你全身肌肉暴起，双目圆睁，腰马和一，一声大喝，一个火球从你宽阔的巨掌中摇晃飞出；当你使用本资源代替里相关属性/技能进行施法时，你的所有法术都具有【成分：姿势】。</p><p>“waghhhhh ，动起来啊，快动啊，给我发射！”你在操作台前大声吼叫，粗暴的晃动遥杆，瞎几把按下按钮，载具/火炮/电脑竟然真的就此运行起来了：当你使用本资源代替相关属性/技能进行操控时，可以以欧克兽人看了都直呼内行的瞎几把操作达成目的。但st有权在几轮如此粗暴的操作后，给你一点剧情上的（比如飞机的起落架掉了，汽车的刹车没了）等可以让你专心操纵不留遗憾的特殊照顾。</p><p>选开：当人物被动的需要以智力进行对抗时，你可以以一个自由动作对场景内的所有生物进行屈辱（骄傲）的宣言“老子没有智力！”此时，场景内的所有敌人都会相信，你是个智力1的蠢货，没了毛的肌肉大猩猩，并产生来自智力压制的有优越感，这是无支线等级的心灵影响；当你如此宣言后，本场景内，你可以使用力量代替智力参与相关所有检定与对抗。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
